Input.value:
{
                        path: 'claim>/claim_item/meter_cube_actual',
                        type: 'FloatType',
                        formatOptions: {
                            minFractionDigits: 2,
                            maxFractionDigits: 2,
                            maxIntegerDigits: 16,
                            preserveDecimals: false
                        },
                        constraints: {
                            minimum: 0.01
                        }
                    }

{
						path: 'claim>/claim_item/actual_amount',
						type: 'FloatType',
						formatOptions: {
							minFractionDigits: 2,
							maxFractionDigits: 2,
							maxIntegerDigits: 16,
							preserveDecimals: false
						},
						constraints: {
							minimum: 0.01
						}
					}

{
						path: 'claim>/claim_item/request_approval_amount',
						type: 'FloatType',
						formatOptions: {
							minFractionDigits: 2,
							maxFractionDigits: 2,
							preserveDecimals: false
						}
					}

Text.text:
{
						path: 'claim>/claim_item/eligible_amount',
						type: 'FloatType',
						formatOptions: {
							minFractionDigits: 2,
							maxFractionDigits: 2,
							maxIntegerDigits: 16,
							preserveDecimals: false
						}
					}

Input.value:
{
						path: 'claim>/claim_item/percentage_compensation',
						type: 'FloatType',
						formatOptions: {
							minFractionDigits: 1,
							maxFractionDigits: 2,
							maxIntegerDigits: 5,
							preserveDecimals: false
						}
					}

DatePicker.value:
{
						path: 'claim>/claim_item/receipt_date',
						type: 'sap.ui.model.type.Date',
						formatOptions:{
							source:{
								pattern:'yyyy-MM-dd'
							},
							pattern:'dd-MMM-yyyy'
						}
					}

{
                        path: 'claim>/claim_item/start_date',
                        type: 'sap.ui.model.type.Date',
                        formatOptions:{
							source:{
								pattern:'yyyy-MM-dd'
							},
							pattern:'dd-MMM-yyyy'
						}
                    }

{
                        path: 'claim>/claim_item/end_date',
                        type: 'sap.ui.model.type.Date',
                        formatOptions:{
							source:{
								pattern:'yyyy-MM-dd'
							},
							pattern:'dd-MMM-yyyy'
						}
                    }

Select.items:
{
                        path: 'employee>/ZTRANSFER_MODE',
                        sorter: [{ path: 'TRANSFER_MODE_ID' }],
                        filters: [{ path: 'STATUS', operator: 'EQ', value1: 'ACTIVE' }]
                    }

Input.value:
{
						path: 'claim>/claim_item/toll',
						type: 'FloatType',
						formatOptions: {
							minFractionDigits: 2,
							maxFractionDigits: 2,
							maxIntegerDigits: 16,
							preserveDecimals: false
                        },
                        constraints: { minimum: 0.00 }
					}

{
						path: 'claim>/claim_item/km',
