							minFractionDigits: 2,
							maxFractionDigits: 2,
							maxIntegerDigits: 6,
							preserveDecimals: false
                        },
                        constraints: { minimum: 0.01 }
					}

{
						path: 'claim>/claim_item/amount',
						type: 'FloatType',
